<?php
if(session_status()===PHP_SESSION_NONE)session_start();header('Content-Type: application/json; charset=utf-8');require_once __DIR__.'/../../config/database.php';
$data=json_decode(file_get_contents('php://input'),true);$items=$data['items']??[];$tableId=filter_var($data['table_id']??null,FILTER_VALIDATE_INT);$type=$data['order_type']??'surplace';$notes=trim($data['notes']??'')?:null;
function clientOrderResponse(bool $ok,string $message,array $extra=[]):void{echo json_encode(array_merge(['success'=>$ok,'message'=>$message],$extra),JSON_UNESCAPED_UNICODE);exit;}
if(!$tableId||!is_array($items)||!$items||!in_array($type,['surplace','a emporter','livraison'],true))clientOrderResponse(false,'Table, type de commande ou panier invalide.');
if(!fetchOne('SELECT id FROM tables WHERE id=:id AND supprimer=0 AND is_active=1',[':id'=>$tableId]))clientOrderResponse(false,'La table sélectionnée est indisponible.');
global $pdo;try{$pdo->beginTransaction();$validated=[];$total=0;foreach($items as $item){$menuId=filter_var($item['id']??null,FILTER_VALIDATE_INT);$qty=filter_var($item['quantity']??null,FILTER_VALIDATE_INT);if(!$menuId||!$qty||$qty<1||$qty>50)throw new Exception('Un article du panier est invalide.');$menu=fetchOne('SELECT id,nom,price,is_available FROM menus WHERE id=:id AND supprimer=0 FOR UPDATE',[':id'=>$menuId]);if(!$menu||!$menu->is_available)throw new Exception('Le plat demandé n’est plus disponible.');$validated[]=['menu'=>$menu,'quantity'=>$qty];$total+=(float)$menu->price*$qty;}$number='IS-'.date('ymd').'-'.strtoupper(bin2hex(random_bytes(2)));$orderId=executeInsert('INSERT INTO orders(order_number,table_id,user_id,total_amount,status,payment_status,order_type,special_notes) VALUES(:number,:table,:user,:total,"en attente","en attente",:type,:notes)',[':number'=>$number,':table'=>$tableId,':user'=>$_SESSION['user_id']??null,':total'=>$total,':type'=>$type,':notes'=>$notes]);if(!$orderId)throw new Exception('Impossible de créer la commande.');foreach($validated as $row)executeInsert('INSERT INTO order_items(order_id,menu_id,quantity,unit_price) VALUES(:order,:menu,:qty,:price)',[':order'=>$orderId,':menu'=>$row['menu']->id,':qty'=>$row['quantity'],':price'=>$row['menu']->price]);$pdo->commit();clientOrderResponse(true,'Commande envoyée avec succès.',['order_number'=>$number,'order_id'=>$orderId,'total'=>$total]);}catch(Throwable $e){if($pdo->inTransaction())$pdo->rollBack();clientOrderResponse(false,$e->getMessage());}
